const TutorialOverlay = ({ step, onComplete }: { step: string, onComplete: () => void }) => {
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const requestRef = useRef<number>(null);

    const updateRect = useCallback(() => {
        let id = '';
        if (step === 'MARKET_GUIDE') id = 'MARKET_TAB';
        else if (step === 'FURNACE_GUIDE') id = 'FURNACE_ITEM';

        const el = document.querySelector(`[data-tutorial-id="${id}"]`);
        if (el) {
            setTargetRect(el.getBoundingClientRect());
        } else {
            setTargetRect(null);
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [step]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    if (!targetRect) return null;

    const { top, left, width, height } = targetRect;
    const centerX = left + width / 2;
    const centerY = top + height / 2;
    const radius = Math.max(width, height) / 1.5;

    const label = step === 'MARKET_GUIDE' ? 'Visit the Market' : 'Restore the Furnace';

    return (
        <div className="fixed inset-0 z-[2000] pointer-events-none overflow-hidden">
            {/* Spotlight Mask using SVG for cleaner hole */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs>
                    <mask id="tutorial-mask">
                        <rect width="100%" height="100%" fill="white" />
                        <circle cx={centerX} cy={centerY} r={radius} fill="black" />
                    </mask>
                </defs>
                <rect width="100%" height="100%" fill="rgba(0,0,0,0.7)" mask="url(#tutorial-mask)" />
            </svg>

            {/* Hand Pointer Icon */}
            <div 
                className="absolute transition-all duration-300 ease-out"
                style={{ 
                    left: centerX, 
                    top: top + height + 10,
                    transform: 'translateX(-50%)'
                }}
            >
                <div className="flex flex-col items-center animate-bounce">
                    <Pointer className="w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]" />
                    <span className="mt-2 px-3 py-1 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase tracking-widest rounded-full shadow-2xl whitespace-nowrap">
                        {label}
                    </span>
                </div>
            </div>

            {/* Animated Ring around the spotlight */}
            <div 
                className="absolute border-2 border-amber-400/50 rounded-full animate-ping pointer-events-none"
                style={{
                    left: centerX - radius,
                    top: centerY - radius,
                    width: radius * 2,
                    height: radius * 2
                }}
            />
        </div>
    );
};

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const { state, actions } = useGame();
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);
    }
  }, []);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  // --- BACKGROUND SERVICES ---
  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;

  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  // Tab Button Helper
  const renderTabButton = (tab: { id: typeof activeTab, icon: any, label: string, badge?: number }) => {
    const { id, icon: Icon, label, badge: badgeCount } = tab;
    const isActive = activeTab === id;
    const isUnlocked = state.unlockedTabs.includes(id);
    const isHighlighted = state.tutorialStep === 'MARKET_GUIDE' && id === 'MARKET';

    const handleTabClick = () => {
        if (!isUnlocked) {
            let message = "This facility needs restoration.";
            if (id === 'SHOP') message = "Install a Furnace to open the Shop Counter.";
            if (id === 'INVENTORY') message = "Acquire your first material or perform repairs to track inventory.";
            if (id === 'TAVERN') message = "Rest until Day 2 to welcome travelers at the Tavern.";
            if (id === 'DUNGEON') message = "Hire a mercenary at the Tavern to explore dungeons.";
            actions.showToast(message);
            return;
        }

        if (isHighlighted) {
            // Market 클릭 시 다음 가이드 단계(Furnace 찾기)로 전환
            actions.setTutorialStep('FURNACE_GUIDE');
        }
        setActiveTab(id);
    };

    return (
        <button 
            onClick={handleTabClick}
            key={id}
            data-tutorial-id={id === 'MARKET' ? 'MARKET_TAB' : undefined}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-[2100]' 
                : 'border-transparent text-stone-500 hover:text-stone-300'
            } ${!isUnlocked ? 'grayscale opacity-40 cursor-not-allowed' : 'hover:bg-stone-800/30'} ${isHighlighted ? 'opacity-100 grayscale-0 z-[2100] bg-amber-500/10 border-amber-400' : ''}`}
        >
            <Icon className={`w-4 h-4 md:w-5 md:h-5 z-10 ${isActive ? 'scale-110' : ''}`} />
            <span className={`font-bold tracking-wide text-[10px] md:text-sm uppercase z-10`}>{label}</span>

            {!isUnlocked && (
                <LockIcon className="w-3 h-3 text-stone-600 ml-0.5" />
            )}

            {isUnlocked && badgeCount && badgeCount > 0 ? (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in z-20">
                    {badgeCount}
                </div>
            ) : null}
        </button>
    );
  };

  const allTabs = [
    { id: 'FORGE' as const, icon: Anvil, label: 'Forge' },
    { id: 'MARKET' as const, icon: ShoppingBag, label: 'Market' },
    { id: 'INVENTORY' as const, icon: Package, label: 'Items' },
    { id: 'SHOP' as const, icon: Coins, label: 'Shop', badge: activeTab !== 'SHOP' ? totalShopVisitors : 0 },
    { id: 'TAVERN' as const, icon: Beer, label: 'Tavern' },
    { id: 'DUNGEON' as const, icon: MapIcon, label: 'Dungeon', badge: completedExpeditionsCount },
    { id: 'SIMULATION' as const, icon: Activity, label: 'Sim' },
  ];

  // --- 0. PROLOGUE CHECK ---
  if (!state.hasCompletedPrologue) {
      return <TutorialScene />;
  }

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      {state.tutorialStep && state.hasCompletedPrologue && (
          <TutorialOverlay step={state.tutorialStep} onComplete={() => actions.setTutorialStep(null)} />
      )}

      {/* Top Section Wrapper */}
      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        {/* Tab Navigation Wrapper */}
        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          <div 
            className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${
                showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                onClick={() => scrollTabs('LEFT')}
                className="relative h-full w-full flex items-center pl-2 group/arrow"
              >
                <ChevronLeft className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
              </button>
          </div>

          <div 
            ref={scrollRef}
            onScroll={updateArrows}
            className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain"
            style={{ WebkitOverflowScrolling: 'touch' }}
          >
            {allTabs.map(tab => renderTabButton(tab))}
          </div>

          <div 
            className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${
                showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                onClick={() => scrollTabs('RIGHT')}
                className="relative h-full w-full flex items-center justify-end pr-2 group/arrow"
              >
                <ChevronRight className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
              </button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}>
            <ForgeTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}>
            <ShopTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'INVENTORY' ? 'block' : 'hidden'}`}>
            <InventoryDisplay />
        </div>
        <div className={`h-full w-full ${activeTab === 'MARKET' ? 'block' : 'hidden'}`}>
            <MarketTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'TAVERN' ? 'block' : 'hidden'}`}>
            <TavernTab />
        </div>
        <div className={`h-full w-full ${activeTab === 'DUNGEON' ? 'block' : 'hidden'}`}>
            <DungeonTab />
        </div>
        <div className={`h-full w-full ${activeTab === 'SIMULATION' ? 'block' : 'hidden'}`}>
            <SimulationTab />
        </div>
      </main>

      {/* Toast Notification Container */}
      {state.toast?.visible && (
        <div 
            onClick={actions.hideToast}
            className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]"
        >
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>

      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        onQuit={onQuit} 
        onLoadRequest={onLoadFromSettings}
      />
    </div>
  );
};

export default MainGameLayout;

import React, { useState, useMemo, useRef } from 'react';
import { useGame } from '../../../context/GameContext';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  AlertCircle,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  CreditCard,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);

  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  // 롱터치 가속 관련 Ref
  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace, hasWorkbench } = state.forge;
  const currentTier = state.stats.tierLevel;

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    // 튜토리얼 중 용광로를 클릭하면 가이드 종료
    if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep(null);
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const handleBuy = () => {
    if (cartItemCount === 0) {
      actions.showToast("Your cart is empty.");
      return;
    }
    if (totalCost > state.stats.gold) {
      actions.showToast("Insufficient Gold!");
      return;
    }

    const itemsToBuy = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(itemsToBuy, totalCost);
    setCart({});
    actions.showToast("Purchase complete!");
  };

  const setMultiplier = (itemId: string, mult: number) => {
    setItemMultipliers(prev => ({ ...prev, [itemId]: mult }));
  };

  return (
    <div className="h-full w-full flex bg-stone-950 relative overflow-hidden">
      {/* ✅ 메인 카탈로그: 너비를 w-full로 고정하여 장바구니 상태와 무관하게 일정하게 유지 */}
      <div className="flex flex-col h-full w-full relative shrink-0">
        <div className="bg-stone-900/80 backdrop-blur-md p-3 md:p-5 border-b border-stone-800 flex items-center justify-between z-10 shrink-0">
          <div className="flex items-center gap-2 md:gap-4">
            <div className="bg-amber-900/30 p-1.5 md:p-2.5 rounded-xl border border-amber-700/50">
              <Store className="w-4 h-4 md:w-6 md:h-6 text-amber-500" />
            </div>
            <div>
              <h2 className="text-sm md:text-2xl font-black text-stone-100 font-serif tracking-tight uppercase leading-none">
                Market
              </h2>
              <span className="text-[7px] md:text-[9px] font-mono font-bold text-amber-600 block mt-1 uppercase">
                Tier {currentTier} Supplies
              </span>
            </div>
          </div>

          {/* Quick Pay Button in Header */}
          <div className="flex items-center gap-2">
            <button
              onClick={handleBuy}
              className={`relative flex items-center gap-2 md:gap-3 px-3 md:px-6 py-1.5 md:py-3 rounded-xl border transition-all shadow-lg active:scale-95 group ${
                cartItemCount === 0
                  ? 'bg-stone-800/40 border-stone-700 text-stone-600 grayscale'
                  : totalCost > state.stats.gold
                    ? 'bg-red-900/40 border-red-700 text-red-300'
                    : 'bg-amber-600 hover:bg-amber-500 border-amber-400 text-white shadow-[0_0_20px_rgba(217,119,6,0.2)]'
              }`}
            >
              <div className="relative">
                <ShoppingCart className={`w-3.5 h-3.5 md:w-5 md:h-5 ${cartItemCount > 0 ? 'animate-bounce' : ''}`} />
                {cartItemCount > 0 && (
                  <div className="absolute -top-2 -right-2 bg-red-600 text-white text-[7px] md:text-[9px] font-black px-1 rounded-full border border-stone-900 ring-1 ring-white/20">
                    {cartItemCount}
                  </div>
                )}
              </div>
              <div className="flex flex-col items-start leading-none">
                <span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest">Pay Now</span>
                <div className="flex items-center gap-0.5 mt-0.5">
                  <span className="text-[9px] md:text-sm font-mono font-black">{totalCost}</span>
                  <Coins className="w-2.5 h-2.5 md:w-3 md:h-3 text-amber-200" />
                </div>
              </div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 md:p-6 custom-scrollbar pb-24">
          {/* ✅ 그리드 고정: 컬럼 수를 고정하여 UI 변동 방지 */}
          <div className="grid gap-1.5 md:gap-4 max-w-7xl mx-auto content-start grid-cols-5 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10">
            {MARKET_CATALOG.map(marketItem => {
              const isKeyItem = marketItem.id === 'furnace' || marketItem.id === 'workbench';
              const isScrollItem = marketItem.id.startsWith('scroll_');
              const isOwned =
                (marketItem.id === 'furnace' && state.forge.hasFurnace) ||
                (marketItem.id === 'workbench' && state.forge.hasWorkbench);

              if (isKeyItem && isOwned) return null;

              let itemName = '';
              let itemTier = 1;
              if (marketItem.id === 'furnace') {
                itemName = 'Furnace';
                itemTier = 0;
              } else if (marketItem.id === 'workbench') {
                itemName = 'Workbench';
                itemTier = 1;
              } else if (marketItem.id === 'scroll_t2') {
                itemName = 'Scroll T2';
                itemTier = 1;
                if (currentTier >= 2) return null;
              } else if (marketItem.id === 'scroll_t3') {
                itemName = 'Scroll T3';
                itemTier = 2;
                if (currentTier >= 3) return null;
              } else {
                const itemDef = Object.values(MATERIALS).find(i => i.id === marketItem.id);
                if (!itemDef) return null;
                itemName = (itemDef as any).name;
                itemTier = (itemDef as any).tier || 1;
              }

              if (itemTier > currentTier) return null;

              const stockLeft = (state.marketStock[marketItem.id] || 0) - (cart[marketItem.id] || 0);
              const isSoldOut = stockLeft <= 0;
              const selectedMult = itemMultipliers[marketItem.id] || 1;
              const invCount = state.inventory.find(i => i.id === marketItem.id)?.quantity || 0;

              return (
                <div
                  key={marketItem.id}
                  data-tutorial-id={marketItem.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                  className={`group relative flex flex-col items-center p-1 md:p-2 rounded-lg md:rounded-xl border transition-all h-[130px] md:h-[210px] justify-between overflow-hidden shadow-sm select-none ${
                    pressingItemId === marketItem.id
                      ? 'scale-[0.97] border-amber-500 bg-amber-900/10'
                      : isSoldOut
                        ? 'bg-stone-900 border-stone-800 opacity-60 grayscale'
                        : 'bg-stone-850 border-stone-800'
                  }`}
                >
                  {invCount > 0 && (
                    <div className="absolute top-0.5 left-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-0.5">
                      <Package className="w-1.5 h-1.5 md:w-2 md:h-2" />
                      <span>{invCount}</span>
                    </div>
                  )}

                  <div
                    className={`absolute top-0.5 right-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 ${
                      stockLeft > 0 ? 'bg-emerald-950/60 border-emerald-500/40 text-emerald-400' : 'bg-red-950/60 border-red-500/40 text-red-500'
                    }`}
                  >
                    {isSoldOut ? 'X' : stockLeft}
                  </div>

                  {/* ✅ 아이콘 영역: 크기를 더욱 키움 */}
                  <div
                    className={`flex-1 w-full flex items-center justify-center transition-all relative mt-1 overflow-hidden rounded-lg
                      ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 group-hover:scale-105 active:scale-95'}
                      touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <img
                      src={getAssetUrl(`${marketItem.id}.png`)}
                      className="w-14 h-14 md:w-26 md:h-26 object-contain drop-shadow-md pointer-events-none"
                      onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.nextElementSibling?.classList.remove('hidden');
                      }}
                      draggable={false}
                    />
                    <div className="hidden text-base md:text-3xl pointer-events-none">📦</div>
                  </div>

                  {!isSoldOut && !isKeyItem && !isScrollItem && (
                    <div
                      className="multiplier-btn flex items-center gap-0.5 md:gap-1 my-1 bg-stone-950/80 p-0.5 rounded-lg border border-stone-800/50 z-20"
                    >
                      {[1, 5, 10].map(m => (
                        <button
                          key={m}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            setMultiplier(marketItem.id, m);
                          }}
                          className={`w-4 h-4 md:w-7 md:h-7 rounded text-[6px] md:text-[9px] font-black transition-all ${
                            selectedMult === m
                              ? 'bg-amber-600 text-white shadow-glow-sm'
                              : 'bg-stone-800 text-stone-500 hover:text-stone-300'
                          }`}
                        >
                          x{m}
                        </button>
                      ))}
                    </div>
                  )}

                  <div className="w-full text-center mb-0.5">
                    <h4
                      className={`text-[7px] md:text-[11px] font-black leading-none truncate px-1 ${
                        isKeyItem || isScrollItem ? 'text-amber-400' : 'text-stone-400'
                      }`}
                    >
                      {itemName}
                    </h4>
                  </div>

                  <div
                    className={`w-full py-0.5 md:py-1 rounded-b-lg border-t flex items-center justify-center gap-0.5 font-mono font-black transition-all
                      text-[7px] md:text-xs
                      ${isSoldOut
                        ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed'
                        : 'bg-stone-950 border-stone-800 text-amber-500 cursor-pointer hover:bg-amber-900/20 active:bg-amber-900/40'
                      }
                      select-none touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <span className="hidden md:inline pointer-events-none">
                      <Coins className="w-2.5 h-2.5" />
                    </span>
                    <span className="pointer-events-none">{marketItem.price}</span>
                  </div>

                  {isSoldOut && (
                    <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/60 backdrop-blur-[0.5px]">
                      <span className="bg-red-600 text-white text-[6px] md:text-[8px] font-black px-1.5 py-0.5 rounded rotate-12 shadow-md">
                        SOLD
                      </span>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* ✅ 장바구니 오버랩 드로어: absolute 포지션으로 카탈로그 위에 덮어씌움 */}
      <div
        className={`absolute top-0 right-0 h-full bg-stone-900/95 backdrop-blur-3xl border-l border-stone-800 shadow-[-10px_0_30px_rgba(0,0,0,0.5)] z-[100] flex flex-col transition-all duration-500 ease-in-out ${
          isCartOpen ? 'w-[85%] sm:w-[50%] md:w-80 translate-x-0' : 'w-0 translate-x-full border-none'
        }`}
      >
        {/* 토글 버튼: 장바구니 패널의 왼쪽에 고정되어 함께 이동 */}
        <button
          onClick={() => setIsCartOpen(!isCartOpen)}
          className={`absolute top-1/2 -left-6 md:-left-8 w-6 md:w-8 h-20 md:h-24 -translate-y-1/2 border-y border-l transition-all z-[110] cursor-pointer shadow-xl rounded-l-lg flex flex-col items-center justify-center 
            ${
              cartItemCount > 0
                ? 'bg-amber-600 border-amber-400 animate-pulse text-white shadow-[0_0_20px_rgba(217,119,6,0.3)]'
                : 'bg-stone-800 border-stone-600 text-stone-400 hover:bg-stone-700 hover:text-amber-400'
            }`}
        >
          <ShoppingCart className="w-3.5 h-3.5 md:w-5 md:h-5" />
          {isCartOpen ? (
            <ChevronRight className="w-3 h-3 md:w-4 md:h-4 mt-1 opacity-50" />
          ) : (
            <ChevronLeft
              className={`w-3 h-3 md:w-4 md:h-4 mt-1 ${
                cartItemCount > 0 ? 'text-white' : 'text-amber-500 animate-pulse'
              }`}
            />
          )}
        </button>

        <div className={`flex flex-col h-full w-full ${isCartOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
          <div className="bg-stone-850 p-3 md:p-4 border-b border-stone-800 flex items-center justify-between shrink-0">
            <h3 className="font-serif font-black text-xs md:text-lg text-stone-100 uppercase tracking-tighter truncate">
              Your Cart
            </h3>
          </div>

          <div className="flex-1 overflow-y-auto p-2 md:p-3 space-y-2.5 custom-scrollbar">
            {Object.keys(cart).length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-700 text-center px-4">
                <ShoppingBag className="w-8 h-8 md:w-10 md:h-10 opacity-10 mb-2" />
                <p className="italic font-medium text-[8px] md:text-[10px] uppercase tracking-widest">Cart is empty</p>
              </div>
            ) : (
              Object.entries(cart).map(([id, count]) => {
                const marketItem = MARKET_CATALOG.find(i => i.id === id);
                const name =
                  id === 'furnace'
                    ? 'Furnace'
                    : id === 'workbench'
                      ? 'Workbench'
                      : MATERIALS[id.toUpperCase() as keyof typeof MATERIALS]?.name || id;

                if (!marketItem) return null;

                return (
                  <div key={id} className="flex items-center gap-2 bg-stone-950 p-2 md:p-3 rounded-xl border border-stone-800 group select-none">
                    <div className="w-10 h-10 md:w-14 md:h-14 bg-stone-900 rounded-lg border border-stone-800 flex items-center justify-center shrink-0">
                      <img src={getAssetUrl(`${id}.png`)} className="w-8 h-8 md:w-11 md:h-11 object-contain" draggable={false} />
                    </div>
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                      <div className="text-stone-100 font-bold text-[10px] md:text-sm truncate">{name}</div>
                      <div className="text-amber-600 font-mono text-[9px] md:text-xs font-bold">{marketItem.price * (count as number)} G</div>
                    </div>
                    <div className="flex items-center gap-1.5 shrink-0 bg-stone-900 rounded-lg border border-stone-700 p-0.5">
                      <button
                        type="button"
                        onClick={() => removeFromCart(id)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Minus className="w-2.5 h-2.5" />
                      </button>
                      <span className="min-w-[16px] text-center font-mono text-stone-200 font-bold text-[10px] md:text-xs">{count}</span>
                      <button
                        type="button"
                        onClick={() => addToCart(id, 1)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Plus className="w-2.5 h-2.5" />
                      </button>
                    </div>
                    <button type="button" onClick={() => deleteFromCart(id)} className="p-1 md:p-1.5 hover:text-red-500 transition-colors">
                      <Trash2 className="w-3 h-3 md:w-4 md:h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>

          <div className="bg-stone-850 p-3 md:p-4 border-t border-stone-800 space-y-3 shrink-0">
            <div className="flex justify-between items-center text-[9px] md:text-sm text-stone-600 font-bold uppercase tracking-tighter">
              <span>Grand Total</span>
              <span className={`text-sm md:text-xl font-mono font-black ${totalCost > state.stats.gold ? 'text-red-500' : 'text-amber-500'}`}>
                {totalCost} G
              </span>
            </div>
            <button
              type="button"
              onClick={handleBuy}
              className={`w-full py-2.5 md:py-3 rounded-xl font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 shadow-xl ${
                totalCost > state.stats.gold ? 'bg-stone-800 text-stone-300' : 
                totalCost === 0 ? 'bg-stone-800 text-stone-500 grayscale opacity-60' :
                'bg-amber-600 hover:bg-amber-500 text-white'
              }`}
            >
              <ShoppingBag className="w-4 h-4" />
              <span>{totalCost > state.stats.gold ? 'Insufficient Funds' : 'Purchase'}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MarketTab;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain, AlertCircle, TrendingUp, Sparkles, FastForward } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent, unlockedRecipes, tutorialStep, hasCompletedPrologue } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [failedFuelHighlight, setFailedFuelHighlight] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getResourceName = (id: string) => {
      const itemDef = Object.values(MATERIALS).find(i => i.id === id);
      return itemDef ? itemDef.name : id;
  };

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image);
    return getAssetUrl(`${item.id}.png`);
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      return hasFuel || hasHeat;
  }, [selectedItem, hasFuel, hasHeat]);

  const requiredEnergy = useMemo(() => {
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
          if (!isUnlocked) return false;
          if (item.tier > stats.tierLevel) return false;
          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, stats.tierLevel, unlockedRecipes]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (visibleSubCats.length > 0 && !expandedSubCat) {
          setExpandedSubCat(visibleSubCats[0].id);
      }
  }, [activeCategory, visibleSubCats, expandedSubCat]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => prev.includes(itemId) ? prev.filter(id => id !== itemId) : [...prev, itemId]);
  }, []);

  const isRequirementMet = useMemo(() => {
    if (!selectedItem) return true;
    if (selectedItem.craftingType === 'FORGE') return hasFurnace;
    if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
    return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;

      // Tiered checks for toast feedback
      if (!isRequirementMet) {
          actions.showToast(`You need a ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'} to craft this.`);
          return;
      }
      if (!canAffordResources(selectedItem)) {
          actions.showToast(`Insufficient materials for ${selectedItem.name}.`);
          return;
      }
      if (!hasEnergy) {
          actions.triggerEnergyHighlight();
          actions.showToast("Not enough energy.");
          return;
      }
      if (selectedItem.craftingType === 'FORGE' && !canEnterForge) {
          setFailedFuelHighlight(true);
          setTimeout(() => setFailedFuelHighlight(false), 2000);
          actions.showToast("Forge is cold! Add fuel first.");
          return;
      }

      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem, isRequirementMet, canAffordResources, hasEnergy, canEnterForge]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) actions.cancelCrafting(selectedItem);
      else actions.setCrafting(false); 
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) actions.finishCrafting(selectedItem, score, bonus);
    setIsPanelOpen(true);
  }, [selectedItem, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const updateTooltipPosition = (x: number, y: number) => {
      const viewportW = window.innerWidth;
      const viewportH = window.innerHeight;
      let finalX = x + 20;
      let finalY = y + 20;
      if (finalX + 240 > viewportW) finalX = x - 260;
      if (finalY + 160 > viewportH) finalY = y - 180;
      setTooltipPos({ x: finalX, y: finalY });
  };

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  const renderStats = (item: EquipmentItem) => {
    if (!item.baseStats) return null;
    const s = item.baseStats;
    return (
        <div className="grid grid-cols-2 gap-1.5 md:gap-3 w-full max-w-xs mb-4 md:mb-6 animate-in slide-in-from-bottom-2 duration-500">
            {s.physicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> P.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalAttack}</span>
                </div>
            )}
            {s.magicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex items-center justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Zap className="w-2.5 h-2.5" /> M.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalAttack}</span>
                </div>
            )}
            {s.physicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex items-center justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> P.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalDefense}</span>
                </div>
            )}
            {s.magicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex items-center justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Brain className="w-2.5 h-2.5" /> M.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalDefense}</span>
                </div>
            )}
        </div>
    );
  };

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;
      return (
        <div 
            key={item.id} onClick={() => setSelectedItem(item)}
            onMouseEnter={(e) => handleMouseEnter(item, e)} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[115px] md:h-[130px] overflow-hidden ${isSelected ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'}`}
        >
            <div className="w-full flex justify-between items-start p-1.5 md:p-2 z-10">
                 <span className={`text-[8px] md:text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>T{item.tier}</span>
                 <button onClick={(e) => toggleFavorite(e, item.id)} className="p-1 rounded-full hover:bg-stone-700 transition-colors"><Heart className={`w-3 h-3 md:w-3.5 md:h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center group-hover:scale-110 transition-transform -mt-2"><img src={getItemImageUrl(item)} className="w-8 h-8 md:w-10 md:h-10 object-contain drop-shadow-md" /></div>
            <div className="w-full text-center pb-1.5 px-1 flex flex-col items-center gap-0.5"><div className={`text-[10px] md:text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>{item.name}</div>{count > 0 && <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-1.5 py-0.5 rounded text-[8px] font-mono text-stone-500 border border-stone-800/50"><Box className="w-2 h-2" /> {count}</div>}</div>
        </div>
      );
  };

  // --- Mastery Radial Logic ---
  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;
    let nextMax = MASTERY_THRESHOLDS.ADEPT;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
      nextMax = 50; 
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
      nextMax = MASTERY_THRESHOLDS.ARTISAN;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
      nextMax = MASTERY_THRESHOLDS.ADEPT;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count, nextMax };
  }, [selectedItem, craftingMastery]);

  const quickCraftFuelCost = useMemo(() => {
      if (!selectedItem || selectedItem.craftingType !== 'FORGE' || !masteryInfo) return 0;
      const count = masteryInfo.count;
      let divisor = 8;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) divisor = 14;
      else if (count >= MASTERY_THRESHOLDS.ADEPT) divisor = 12;
      return Math.ceil(selectedItem.maxDurability / divisor);
  }, [selectedItem, masteryInfo]);

  const handleQuickCraft = useCallback(() => {
      if (!selectedItem || !masteryInfo) return;

      // Tiered checks for Quick Craft
      if (!isRequirementMet) {
          actions.showToast(`You need a ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'} to craft this.`);
          return;
      }
      if (!canAffordResources(selectedItem)) {
          actions.showToast(`Insufficient materials for ${selectedItem.name}.`);
          return;
      }
      if (!hasEnergy) {
          actions.triggerEnergyHighlight();
          actions.showToast("Not enough energy.");
          return;
      }

      // Fuel logic for Smithing Quick Craft
      if (selectedItem.craftingType === 'FORGE') {
          if (charcoalCount < quickCraftFuelCost) {
              actions.showToast(`Insufficient charcoal! Need ${quickCraftFuelCost} fuel.`);
              return;
          }
          actions.consumeItem('charcoal', quickCraftFuelCost);
      }

      // Determine quality and mastery gain based on current rank
      let quality = 50;
      let masteryGain = 0.5;

      if (masteryInfo.count >= MASTERY_THRESHOLDS.ARTISAN) {
          quality = 95;
          masteryGain = 1.0;
      } else if (masteryInfo.count >= MASTERY_THRESHOLDS.ADEPT) {
          quality = 75;
          masteryGain = 0.7;
      }

      // Deduct resources and energy
      actions.startCrafting(selectedItem);
      // Immediately finalize with specific parameters
      actions.finishCrafting(selectedItem, quality, 0, masteryGain);
  }, [selectedItem, masteryInfo, isRequirementMet, canAffordResources, hasEnergy, actions, charcoalCount, quickCraftFuelCost]);

  const content = useMemo(() => {
    const canCraft = selectedItem && canAffordResources(selectedItem) && (selectedItem.craftingType === 'WORKBENCH' || canEnterForge) && hasEnergy && isRequirementMet;
    const canQuickCraft = selectedItem && canAffordResources(selectedItem) && hasEnergy && isRequirementMet && (selectedItem.craftingType !== 'FORGE' || charcoalCount >= quickCraftFuelCost);
    const isMissingFuelOnly = selectedItem && selectedItem.craftingType === 'FORGE' && canAffordResources(selectedItem) && !canEnterForge && hasEnergy && isRequirementMet;
    const hasAlreadyCraftedOnce = selectedItem ? (craftingMastery[selectedItem.id] || 0) > 0 : false;

    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden" style={{ backgroundImage: `url(${getAssetUrl('tile_forge.png')})`, backgroundRepeat: 'repeat', backgroundBlendMode: 'multiply' }}>

        {selectedItem && !isRequirementMet && (
            <div className="absolute inset-0 z-[60] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-stone-950/90 backdrop-blur-md animate-in fade-in duration-700"></div>
                <div className="relative z-10 p-6 md:p-8 max-w-md w-full bg-stone-900 border-2 border-stone-800 rounded-2xl shadow-2xl flex flex-col items-center text-center animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto">
                    <button onClick={() => setSelectedItem(null)} className="absolute top-4 right-4 p-2 text-stone-500 hover:text-stone-300 transition-colors"><X className="w-5 h-5" /></button>
                    <div className="w-16 h-16 md:w-20 md:h-20 bg-stone-800 rounded-full flex items-center justify-center mb-4 md:mb-6 border border-stone-700 shrink-0">{selectedItem.craftingType === 'FORGE' ? <Flame className="w-8 h-8 md:w-10 md:h-10 text-stone-600" /> : <Wrench className="w-8 h-8 md:w-10 md:h-10 text-stone-600" />}</div>
                    <h2 className="text-xl md:text-2xl font-bold text-stone-300 font-serif mb-2">{selectedItem.craftingType === 'FORGE' ? 'Furnace Required' : 'Workbench Required'}</h2>
                    <p className="text-sm md:text-base text-stone-500 mb-6 md:mb-8 leading-relaxed">Crafting <span className="text-amber-500 font-bold">{selectedItem.name}</span> requires a functional {selectedItem.craftingType === 'FORGE' ? 'furnace' : 'workbench'}. Visit the market to purchase one.</p>
                    <button onClick={() => onNavigate('MARKET')} className="w-full py-3 md:py-4 bg-amber-700 hover:bg-amber-600 text-amber-50 font-bold rounded-xl shadow-lg hover:shadow-amber-900/40 transition-all flex items-center justify-center gap-2 group shrink-0">Go to Market <ChevronRight className="w-4 h-4 md:w-5 md:h-5 group-hover:translate-x-1 transition-transform" /></button>
                </div>
            </div>
        )}
        <div className={`absolute inset-0 z-0 flex w-full h-full ${((selectedItem && !isRequirementMet) || !hasFurnace) ? 'blur-sm pointer-events-none' : ''}`}>
            <div className={`h-full relative flex flex-col transition-all duration-500 ease-in-out ${isPanelOpen ? 'w-[55%] md:w-[60%]' : 'w-full'}`}>
                <div className="w-full h-full flex flex-col items-center justify-center p-4 md:p-8 bg-stone-925/40 relative overflow-hidden">
                    <div className="absolute inset-0 opacity-10 pointer-events-none flex items-center justify-center">{selectedItem?.craftingType === 'FORGE' ? <Hammer className="w-64 h-64 md:w-96 md:h-96 text-stone-500" /> : <Wrench className="w-64 h-64 md:w-96 md:h-96 text-stone-500" />}</div>
                    {selectedItem ? (
                        <div className="z-10 flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full max-w-lg">

                            {/* Mastery Radial Indicator around item image */}
                            <div className="relative mb-3 md:mb-6 group">
                                <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-full flex items-center justify-center relative z-10 p-2 md:p-4 border border-stone-800/50 ${masteryInfo?.glowClass} transition-all duration-700`}>
                                    {/* Radial SVG Gauge */}
                                    <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none" viewBox="0 0 100 100">
                                        {/* Background Track */}
                                        <circle cx="50" cy="50" r="46" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-stone-950/40" />
                                        {/* Progress Arc */}
                                        <circle 
                                            cx="50" cy="50" r="46" 
                                            stroke="currentColor" strokeWidth="4" fill="transparent"
                                            strokeDasharray={masteryInfo?.circumference}
                                            strokeDashoffset={masteryInfo?.offset}
                                            strokeLinecap="round"
                                            className={`${masteryInfo?.colorClass} transition-all duration-1000 ease-out`}
                                        />
                                    </svg>
                                    <img src={getItemImageUrl(selectedItem)} className="w-14 h-14 md:w-32 md:h-32 object-contain drop-shadow-2xl z-20 relative transform group-hover:scale-110 transition-transform duration-500" />

                                    {/* Small Rank Badge */}
                                    <div className={`absolute -bottom-1 -right-1 md:bottom-2 md:right-2 z-30 px-1.5 py-0.5 md:px-2.5 md:py-1 rounded-full border border-stone-700 bg-stone-900 shadow-xl flex items-center gap-1 animate-in slide-in-from-right-2 duration-700`}>
                                        <Star className={`w-2 h-2 md:w-3 md:h-3 ${masteryInfo?.colorClass.replace('stroke-', 'fill-')}`} />
                                        <span className={`text-[7px] md:text-[10px] font-black uppercase tracking-tighter ${masteryInfo?.colorClass.replace('stroke-', 'text-')}`}>{masteryInfo?.label}</span>
                                    </div>
                                </div>
                            </div>

                            <h2 className="text-xl md:text-3xl font-bold text-amber-500 mb-1 md:mb-1.5 font-serif tracking-wide">{selectedItem.name}</h2>
                            <p className="text-stone-500 text-center max-w-md mb-4 md:mb-6 italic text-[9px] md:text-sm leading-tight px-6">"{selectedItem.description}"</p>

                            {/* Stats Block */}
                            {renderStats(selectedItem)}

                            {/* Modified Mastery Info (Simplified Text since circle handles visual) */}
                            <div className="w-full max-w-xs mb-6 md:mb-8 flex flex-col items-center">
                                <div className="flex items-center gap-1.5 text-[8px] md:text-[10px] font-black uppercase tracking-widest text-stone-500 mb-1">
                                    <Award className="w-3 h-3 md:w-4 md:h-4 text-amber-600" />
                                    <span>Experience: {Math.round(masteryInfo?.progress || 0)}%</span>
                                </div>
                            </div>

                            <div className="relative group flex flex-col items-center w-full gap-2 md:gap-4 px-4">
                                {/* Persistent Fuel Warning */}
                                {isMissingFuelOnly && (
                                    <div className="mb-2 flex items-center gap-1.5 text-orange-500 font-bold text-[9px] md:text-xs animate-pulse bg-orange-950/30 px-3 py-1 rounded-full border border-orange-900/40">
                                        <Flame className="w-3 h-3 md:w-4 md:h-4" />
                                        <span>Fuel Required to Heat the Forge</span>
                                    </div>
                                )}

                                <div className="flex flex-col sm:flex-row gap-3 w-full justify-center">
                                    <button 
                                        onClick={startCrafting} 
