import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { getAssetUrl } from '../../../utils';
import { TutorialSceneMode } from '../../../types/game-state';

const SCRIPTS: Record<TutorialSceneMode, { text: string; highlight?: string }[]> = {
    PROLOGUE: [
        { text: "I have just returned from the hill after burying my family... My hands, stained with earth, are still trembling." },
        { text: "The forge has been ruthlessly trampled by their hands. Everything I built... gone in a single night of fire and blood." },
        { text: "But the fury within me burns hotter than any flame. For the sake of vengeance, I will rekindle the embers of this forge once more." },
        { text: "Wait... the furnace is completely beyond repair. I cannot melt ore without a steady flame.", highlight: "furnace" },
        { text: "I must head to the Market immediately to find a replacement. The hammer of the Lockhart lineage will not be silenced." }
    ],
    FURNACE_RESTORED: [
        { text: "The furnace is finally in place. The air in the forge doesn't feel so heavy and cold anymore." },
        { text: "It's a sturdy unit. I've managed to seal the connections, but I should check if the flue is drawing correctly." },
        { text: "Good... the draft is steady. Now all I need is a bit of fuel and heat to start forging properly once more." }
    ]
};

const TutorialScene: React.FC = () => {
    const { state, actions } = useGame();
    const [isStarted, setIsStarted] = useState(false);
    const [currentStep, setCurrentStep] = useState(0);
    const [hasSwapped, setHasSwapped] = useState(false);
    const [showFlash, setShowFlash] = useState(false);

    const mode = state.activeTutorialScene || 'PROLOGUE';
    const script = SCRIPTS[mode];

    // Background logic: Start with ruined even in RESTORED mode until tapped
    const bgImage = (mode === 'PROLOGUE' || !hasSwapped) 
        ? 'forge_ruined_bg.png' 
        : 'forge_fixed_bg.png';

    const promptText = mode === 'FURNACE_RESTORED' ? "Replace Furnace" : "Tap to Begin";

    const handleNext = () => {
        if (currentStep < script.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            if (mode === 'PROLOGUE') {
                actions.completePrologue();
            } else {
                actions.setTutorialStep(null);
                actions.setTutorialScene(null);
            }
        }
    };

    const startTutorial = () => {
        if (!isStarted) {
            if (mode === 'FURNACE_RESTORED') {
                // Trigger visual transition for replacing furnace
                setShowFlash(true);
                setTimeout(() => {
                    setHasSwapped(true);
                    setIsStarted(true);
                }, 200); // Swap mid-flash
                setTimeout(() => {
                    setShowFlash(false);
                }, 1000);
            } else {
                setIsStarted(true);
            }
        }
    };

    return (
        <div 
            className="fixed inset-0 z-[3000] bg-stone-950 overflow-hidden animate-in fade-in duration-1000 flex flex-col items-center justify-center cursor-pointer"
            onClick={startTutorial}
        >
            {/* Background Layer */}
            <div className="absolute inset-0 z-0 pointer-events-none bg-stone-950">
                <img 
                    key={bgImage}
                    src={getAssetUrl(bgImage)} 
                    alt="Forge Backdrop" 
                    className="w-full h-full object-cover object-center opacity-60 scale-105 transition-all duration-1000"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.parentElement!.style.background = 'radial-gradient(circle at center, #292524 0%, #0c0a09 100%)';
                    }}
                />
                <div className="absolute inset-0 bg-stone-950/20 backdrop-blur-[1px]"></div>
            </div>

            {/* Atmosphere Effects */}
            <div className="absolute inset-0 pointer-events-none z-10">
                <div className="w-full h-full opacity-30 animate-pulse bg-amber-900/5"></div>
                <div className="absolute inset-0 overflow-hidden">
                   <div 
                        className="absolute top-0 left-0 w-full h-[200%] opacity-15" 
                        style={{ 
                            backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', 
                            backgroundSize: '100px 100px',
                            animation: 'ash-fall 35s linear infinite'
                        }}
                    ></div>
                </div>
            </div>

            {/* Transition Flash Overlay */}
            {showFlash && (
                <div className="absolute inset-0 z-[100] bg-white animate-flash-out pointer-events-none"></div>
            )}

            {/* Start Prompt */}
            {!isStarted && !showFlash && (
                <div className="relative z-20 flex flex-col items-center animate-pulse">
                    <span className="text-amber-500 font-black uppercase tracking-[0.4em] text-[10px] md:text-sm drop-shadow-[0_0_10px_rgba(245,158,11,0.5)]">
                        {promptText}
                    </span>
                </div>
            )}

            {/* Dialogue Box */}
            {isStarted && (
