  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);
    }
  }, []);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  // --- BACKGROUND SERVICES ---
  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;

  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  // Tab Button Helper
  const renderTabButton = (tab: { id: typeof activeTab, icon: any, label: string, badge?: number }) => {
    const { id, icon: Icon, label, badge: badgeCount } = tab;
    const isActive = activeTab === id;
    const isUnlocked = state.unlockedTabs.includes(id);
    const isHighlighted = (state.tutorialStep === 'MARKET_GUIDE' && id === 'MARKET') || 
                         (state.tutorialStep === 'FORGE_TAB_GUIDE' && id === 'FORGE');

    const handleTabClick = () => {
        if (!isUnlocked) {
            let message = "This facility needs restoration.";
            if (id === 'SHOP') message = "Install a Furnace to open the Shop Counter.";
            if (id === 'INVENTORY') message = "Acquire your first material or perform repairs to track inventory.";
            if (id === 'TAVERN') message = "Rest until Day 2 to welcome travelers at the Tavern.";
            if (id === 'DUNGEON') message = "Hire a mercenary at the Tavern to explore dungeons.";
            actions.showToast(message);
            return;
        }

        if (state.tutorialStep === 'MARKET_GUIDE' && id === 'MARKET') {
            actions.setTutorialStep('FURNACE_GUIDE');
        } else if (state.tutorialStep === 'FORGE_TAB_GUIDE' && id === 'FORGE') {
            actions.setTutorialStep('SELECT_SWORD_GUIDE');
        }
        setActiveTab(id);
    };

    return (
        <button 
            onClick={handleTabClick}
            key={id}
            data-tutorial-id={id === 'MARKET' ? 'MARKET_TAB' : id === 'FORGE' ? 'FORGE_TAB' : undefined}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-[2100]' 
                : 'border-transparent text-stone-500 hover:text-stone-300'
            } ${!isUnlocked ? 'grayscale opacity-40 cursor-not-allowed' : 'hover:bg-stone-800/30'} ${isHighlighted ? 'opacity-100 grayscale-0 z-[2100] bg-amber-500/10 border-amber-400 shadow-[0_0_20px_rgba(245,158,11,0.2)]' : ''}`}
        >
            <Icon className={`w-4 h-4 md:w-5 md:h-5 z-10 ${isActive ? 'scale-110' : ''}`} />
            <span className={`font-bold tracking-wide text-[10px] md:text-sm uppercase z-10`}>{label}</span>

            {!isUnlocked && (
                <LockIcon className="w-3 h-3 text-stone-600 ml-0.5" />
            )}

            {isUnlocked && badgeCount && badgeCount > 0 ? (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in z-20">
                    {badgeCount}
                </div>
            ) : null}
        </button>
    );
  };

  const allTabs = [
    { id: 'FORGE' as const, icon: Anvil, label: 'Forge' },
    { id: 'MARKET' as const, icon: ShoppingBag, label: 'Market' },
    { id: 'INVENTORY' as const, icon: Package, label: 'Items' },
    { id: 'SHOP' as const, icon: Coins, label: 'Shop', badge: activeTab !== 'SHOP' ? totalShopVisitors : 0 },
    { id: 'TAVERN' as const, icon: Beer, label: 'Tavern' },
    { id: 'DUNGEON' as const, icon: MapIcon, label: 'Dungeon', badge: completedExpeditionsCount },
    { id: 'SIMULATION' as const, icon: Activity, label: 'Sim' },
  ];

  // --- 0. TUTORIAL/PROLOGUE CHECK ---
  if (state.activeTutorialScene) {
      return <TutorialScene />;
  }

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      {state.tutorialStep && state.hasCompletedPrologue && (
          <TutorialOverlay step={state.tutorialStep} />
      )}

      {/* Global Craft Prompt Dialogue */}
      {state.tutorialStep === 'CRAFT_PROMPT' && (
          <div className="fixed inset-0 z-[2500] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
              <div className="w-full max-w-4xl">
                  <DialogueBox 
                    speaker="Lockhart"
                    text="The heat is steady... I can feel the ancient rhythm returning to my arms. I know the blueprints for a Bronze Shortsword. I should craft one to test the new furnace."
                    options={[{ 
                        label: "Continue", 
                        action: () => actions.setTutorialStep('FORGE_TAB_GUIDE'),
                        variant: 'primary' 
                    }]}
                  />
              </div>
          </div>
      )}

      {/* Global Craft Result Dialogue */}
      {state.tutorialStep === 'CRAFT_RESULT_PROMPT' && (
          <div className="fixed inset-0 z-[2500] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
              <div className="w-full max-w-4xl">
                  <DialogueBox 
                    speaker="Lockhart"
                    text="The blade is tempered. Take a look at the quality and stats. The better my performance in the forge, the sharper the edge. Mercenaries will pay highly for superior work."
                    options={[{ 
                        label: "Continue", 
                        action: () => actions.setTutorialStep('FINALIZE_FORGE_GUIDE'),
                        variant: 'primary' 
                    }]}
                  />
              </div>
          </div>
      )}

      {/* Top Section Wrapper */}
      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        {/* Tab Navigation Wrapper */}
        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          <div className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'}`}>
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('LEFT')} className="relative h-full w-full flex items-center pl-2 group/arrow"><ChevronLeft className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" /></button>
          </div>

          <div ref={scrollRef} onScroll={updateArrows} className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain" style={{ WebkitOverflowScrolling: 'touch' }}>{allTabs.map(tab => renderTabButton(tab))}</div>

          <div className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'}`}>
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button onClick={() => scrollTabs('RIGHT')} className="relative h-full w-full flex items-center justify-end pr-2 group/arrow"><ChevronRight className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" /></button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}><ForgeTab onNavigate={setActiveTab} /></div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}><ShopTab onNavigate={setActiveTab} /></div>
        <div className={`h-full w-full ${activeTab === 'INVENTORY' ? 'block' : 'hidden'}`}><InventoryDisplay /></div>
        <div className={`h-full w-full ${activeTab === 'MARKET' ? 'block' : 'hidden'}`}><MarketTab onNavigate={setActiveTab} /></div>
        <div className={`h-full w-full ${activeTab === 'TAVERN' ? 'block' : 'hidden'}`}><TavernTab /></div>
        <div className={`h-full w-full ${activeTab === 'DUNGEON' ? 'block' : 'hidden'}`}><DungeonTab /></div>
        <div className={`h-full w-full ${activeTab === 'SIMULATION' ? 'block' : 'hidden'}`}><SimulationTab /></div>
      </main>

      {/* Toast Notification Container */}
      {state.toast?.visible && (
        <div onClick={actions.hideToast} className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]">
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>
      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onQuit={onQuit} onLoadRequest={onLoadFromSettings} />
    </div>
  );
};

export default MainGameLayout;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain, AlertCircle, TrendingUp, Sparkles, FastForward } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent, unlockedRecipes, tutorialStep, hasCompletedPrologue } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [failedFuelHighlight, setFailedFuelHighlight] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getResourceName = (id: string) => {
      const itemDef = Object.values(MATERIALS).find(i => i.id === id);
      return itemDef ? itemDef.name : id;
  };

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image);
    return getAssetUrl(`${item.id}.png`);
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      return hasFuel || hasHeat;
  }, [selectedItem, hasFuel, hasHeat]);

  const requiredEnergy = useMemo(() => {
      // Fix: Changed GAME_COST to GAME_CONFIG to correctly reference imported constant
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
          if (!isUnlocked) return false;
          if (item.tier > stats.tierLevel) return false;
          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, stats.tierLevel, unlockedRecipes]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (visibleSubCats.length > 0 && !expandedSubCat) {
          setExpandedSubCat(visibleSubCats[0].id);
      }
  }, [activeCategory, visibleSubCats, expandedSubCat]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => prev.includes(itemId) ? prev.filter(id => id !== itemId) : [...prev, itemId]);
  }, []);

  const isRequirementMet = useMemo(() => {
    if (!selectedItem) return true;
    if (selectedItem.craftingType === 'FORGE') return hasFurnace;
    if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
    return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;

      // Tiered checks for toast feedback
      if (!isRequirementMet) {
          actions.showToast(`You need a ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'} to craft this.`);
          return;
      }
      if (!canAffordResources(selectedItem)) {
          actions.showToast(`Insufficient materials for ${selectedItem.name}.`);
          return;
      }
      if (!hasEnergy) {
          actions.triggerEnergyHighlight();
          actions.showToast("Not enough energy.");
          return;
      }
      if (selectedItem.craftingType === 'FORGE' && !canEnterForge) {
          setFailedFuelHighlight(true);
          setTimeout(() => setFailedFuelHighlight(false), 2000);
          actions.showToast("Forge is cold! Add fuel first.");
          return;
      }

      if (state.tutorialStep === 'START_FORGING_GUIDE') {
          actions.setTutorialStep(null); // Clear tutorial for minigame
      }

      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem, isRequirementMet, canAffordResources, hasEnergy, canEnterForge, state.tutorialStep]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) actions.cancelCrafting(selectedItem);
      else actions.setCrafting(false); 
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
        actions.finishCrafting(selectedItem, score, bonus);
        // If it was the tutorial sword, show explanation before finalization
        if (selectedItem.id === 'sword_bronze_t1') {
            actions.setTutorialStep('CRAFT_RESULT_PROMPT');
        }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const updateTooltipPosition = (x: number, y: number) => {
      const viewportW = window.innerWidth;
      const viewportH = window.innerHeight;
      let finalX = x + 20;
      let finalY = y + 20;
      if (finalX + 240 > viewportW) finalX = x - 260;
      if (finalY + 160 > viewportH) finalY = y - 180;
      setTooltipPos({ x: finalX, y: finalY });
  };

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  const handleSelectItem = (item: EquipmentItem) => {
      setSelectedItem(item);
      if (state.tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  };

  const renderStats = (item: EquipmentItem) => {
    if (!item.baseStats) return null;
    const s = item.baseStats;
    return (
        <div className="grid grid-cols-2 gap-1.5 md:gap-3 w-full max-w-xs mb-4 md:mb-6 animate-in slide-in-from-bottom-2 duration-500">
            {s.physicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> P.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalAttack}</span>
                </div>
            )}
            {s.magicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex items-center justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Zap className="w-2.5 h-2.5" /> M.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalAttack}</span>
                </div>
            )}
            {s.physicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex items-center justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> P.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalDefense}</span>
                </div>
            )}
            {s.magicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex items-center justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Brain className="w-2.5 h-2.5" /> M.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalDefense}</span>
                </div>
            )}
        </div>
    );
  };

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;
      return (
        <div 
            key={item.id} 
            onClick={() => handleSelectItem(item)}
            data-tutorial-id={item.id === 'sword_bronze_t1' ? 'SWORD_RECIPE' : undefined}
            onMouseEnter={(e) => handleMouseEnter(item, e)} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[115px] md:h-[130px] overflow-hidden ${isSelected ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'}`}
        >
            <div className="w-full flex justify-between items-start p-1.5 md:p-2 z-10">
                 <span className={`text-[8px] md:text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>T{item.tier}</span>
                 <button onClick={(e) => toggleFavorite(e, item.id)} className="p-1 rounded-full hover:bg-stone-700 transition-colors"><Heart className={`w-3 h-3 md:w-3.5 md:h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center group-hover:scale-110 transition-transform -mt-2"><img src={getItemImageUrl(item)} className="w-8 h-8 md:w-10 md:h-10 object-contain drop-shadow-md" /></div>
            <div className="w-full text-center pb-1.5 px-1 flex flex-col items-center gap-0.5"><div className={`text-[10px] md:text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>{item.name}</div>{count > 0 && <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-1.5 py-0.5 rounded text-[8px] font-mono text-stone-500 border border-stone-800/50"><Box className="w-2 h-2" /> {count}</div>}</div>
        </div>
      );
  };

  // --- Mastery Radial Logic ---
  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;
    let nextMax = MASTERY_THRESHOLDS.ADEPT;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
      nextMax = 50; 
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
      nextMax = MASTERY_THRESHOLDS.ARTISAN;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
      nextMax = MASTERY_THRESHOLDS.ADEPT;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count, nextMax };
  }, [selectedItem, craftingMastery]);

  const quickCraftFuelCost = useMemo(() => {
      if (!selectedItem || selectedItem.craftingType !== 'FORGE' || !masteryInfo) return 0;
      const count = masteryInfo.count;
      let divisor = 8;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) divisor = 14;
      else if (count >= MASTERY_THRESHOLDS.ADEPT) divisor = 12;
      return Math.ceil(selectedItem.maxDurability / divisor);
  }, [selectedItem, masteryInfo]);

  const handleQuickCraft = useCallback(() => {
      if (!selectedItem || !masteryInfo) return;

      // Tiered checks for Quick Craft
      if (!isRequirementMet) {
          actions.showToast(`You need a ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'} to craft this.`);
          return;
      }
      if (!canAffordResources(selectedItem)) {
          actions.showToast(`Insufficient materials for ${selectedItem.name}.`);
          return;
      }
      if (!hasEnergy) {
          actions.triggerEnergyHighlight();
          actions.showToast("Not enough energy.");
          return;
      }

      // Fuel logic for Smithing Quick Craft
      if (selectedItem.craftingType === 'FORGE') {
          if (charcoalCount < quickCraftFuelCost) {
              actions.showToast(`Insufficient charcoal! Need ${quickCraftFuelCost} fuel.`);
              return;
          }
          actions.consumeItem('charcoal', quickCraftFuelCost);
      }

      // Determine quality and mastery gain based on current rank
      let quality = 50;
      let masteryGain = 0.5;

      if (masteryInfo.count >= MASTERY_THRESHOLDS.ARTISAN) {
          quality = 95;
          masteryGain = 1.0;
      } else if (masteryInfo.count >= MASTERY_THRESHOLDS.ADEPT) {
          quality = 75;
          masteryGain = 0.7;
      }

      // Deduct resources and energy
      actions.startCrafting(selectedItem);
      // Immediately finalize with specific parameters
      actions.finishCrafting(selectedItem, quality, 0, masteryGain);
  }, [selectedItem, masteryInfo, isRequirementMet, canAffordResources, hasEnergy, actions, charcoalCount, quickCraftFuelCost]);

  const content = useMemo(() => {
