import { handleAddKnownMercenary, handleScoutMercenary, handleHireMercenary, handleFireMercenary, handleAllocateStat, handleUpdateMercenaryStats, handleGiveGift, handleTalkMercenary } from './reducer/mercenary';
import { handleStartExpedition, handleCompleteExpedition, handleClaimExpedition, handleAbortExpedition, handleDismissDungeonResult } from './reducer/expedition';
import { handleEquipItem, handleUnequipItem } from './reducer/equipment';
import { handleStartManualDungeon, handleMoveManualDungeon, handleFinishManualDungeon, handleRescueNPC, handleRetreatManualDungeon } from './reducer/manualDungeon';

export const gameReducer = (state: GameState, action: GameAction): GameState => {
  switch (action.type) {
    // Save & Load
    case 'LOAD_GAME': return action.payload;

    // Repair
    case 'REPAIR_WORK': return handleRepairWork(state);

    // Sleep
    case 'SLEEP': return handleSleep(state);
    case 'CONFIRM_SLEEP': return handleConfirmSleep(state);
    case 'CLOSE_SLEEP_MODAL': return { ...state, showSleepModal: false };

    // Events
    case 'TRIGGER_EVENT': return handleTriggerEvent(state, action.payload);
    case 'CLOSE_EVENT': return handleCloseEvent(state);
    case 'TOGGLE_JOURNAL': return handleToggleJournal(state);

    // Inventory & Market
    case 'ACQUIRE_ITEM': return handleAcquireItem(state, action.payload);
    case 'PAY_COST': return handlePayCost(state, action.payload);
    case 'BUY_MARKET_ITEMS': return handleBuyMarketItems(state, action.payload);
    case 'INSTALL_FURNACE': return handleInstallFurnace(state);
    case 'SELL_ITEM': return handleSellItem(state, action.payload);
    case 'USE_ITEM': return handleUseItem(state, action.payload);

    // Crafting
    case 'START_CRAFTING': return handleStartCrafting(state, action.payload);
    case 'CANCEL_CRAFTING': return handleCancelCrafting(state, action.payload);
    case 'FINISH_CRAFTING': return handleFinishCrafting(state, action.payload);
    case 'DISMISS_CRAFTING_RESULT': return { ...state, lastCraftedItem: null };
    case 'SET_CRAFTING': return handleSetCrafting(state, action.payload);
    case 'UPDATE_FORGE_STATUS': return handleUpdateForgeStatus(state, action.payload);

    // Shop
    case 'TOGGLE_SHOP': return handleToggleShop(state);
    case 'ENQUEUE_CUSTOMER': return handleEnqueueCustomer(state, action.payload);
    case 'NEXT_CUSTOMER': return handleNextCustomer(state);
    case 'DISMISS_CUSTOMER': return handleDismissCustomer(state);

    // Mercenaries
    case 'ADD_KNOWN_MERCENARY': return handleAddKnownMercenary(state, action.payload);
    case 'SCOUT_MERCENARY': return handleScoutMercenary(state, action.payload);
    case 'HIRE_MERCENARY': return handleHireMercenary(state, action.payload);
    case 'FIRE_MERCENARY': return handleFireMercenary(state, action.payload);
    case 'GIVE_GIFT': return handleGiveGift(state, action.payload);
    case 'TALK_MERCENARY': return handleTalkMercenary(state, action.payload);
    case 'ALLOCATE_STAT': return handleAllocateStat(state, action.payload);
    case 'UPDATE_MERCENARY_STATS': return handleUpdateMercenaryStats(state, action.payload);

    // Expedition
    case 'START_EXPEDITION': return handleStartExpedition(state, action.payload);
    case 'COMPLETE_EXPEDITION': return handleCompleteExpedition(state, action.payload);
    case 'CLAIM_EXPEDITION': return handleClaimExpedition(state, action.payload);
    case 'ABORT_EXPEDITION': return handleAbortExpedition(state, action.payload);
    case 'DISMISS_DUNGEON_RESULT': return handleDismissDungeonResult(state);

    // Equipment
    case 'EQUIP_ITEM': return handleEquipItem(state, action.payload);
    case 'UNEQUIP_ITEM': return handleUnequipItem(state, action.payload);

    // Manual Dungeon
    case 'START_MANUAL_DUNGEON': return handleStartManualDungeon(state, action.payload);
    case 'MOVE_MANUAL_DUNGEON': return handleMoveManualDungeon(state, action.payload);
    case 'FINISH_MANUAL_DUNGEON': return handleFinishManualDungeon(state);
    case 'RETREAT_MANUAL_DUNGEON': return handleRetreatManualDungeon(state);
    case 'TOGGLE_MANUAL_DUNGEON_OVERLAY': return { ...state, showManualDungeonOverlay: action.payload };
    case 'RESCUE_NPC': return handleRescueNPC(state, action.payload);

    // Tutorial & Prologue
    case 'SET_TUTORIAL_STEP': return { ...state, tutorialStep: action.payload };
    case 'SET_ACTIVE_TUTORIAL_SCENE': return { ...state, activeTutorialScene: action.payload };
    case 'COMPLETE_PROLOGUE': 
        return { 
            ...state, 
            hasCompletedPrologue: true,
            activeTutorialScene: null,
            tutorialStep: 'MARKET_GUIDE' // Prologue finished, show spotlight
        };
    case 'COMPLETE_TUTORIAL':
        const finalTabs = ['FORGE', 'MARKET', 'INVENTORY', 'SHOP', 'TAVERN', 'DUNGEON', 'SIMULATION'];
        return {
            ...state,
            tutorialStep: null,
            unlockedTabs: finalTabs,
            logs: ["Lockhart's Forge is fully operational. Rebuilding begins now.", ...state.logs]
        };

    // Toast Notifications
    case 'SHOW_TOAST':
        return {
            ...state,
            toast: { message: action.payload, visible: true }
        };
    case 'HIDE_TOAST':
        return {
            ...state,
            toast: state.toast ? { ...state.toast, visible: false } : null
        };

    // UI Effects
    case 'SET_UI_EFFECT':
        return {
            ...state,
            uiEffects: {
                ...state.uiEffects,
                [action.payload.effect]: action.payload.value
            }
        };

    default:
      return state;
  }
};

import { GameState, InventoryItem } from '../../types/index';
import { MATERIALS } from '../../data/materials';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';

export const handleAcquireItem = (state: GameState, payload: { id: string; quantity: number }): GameState => {
    const { id, quantity } = payload;
    const itemDef = Object.values(MATERIALS).find(i => i.id === id);
    if (!itemDef) return state;

    const existingItem = state.inventory.find(i => i.id === id);
    const newInventory = existingItem
    ? state.inventory.map(i => i.id === id ? { ...i, quantity: i.quantity + quantity } : i)
    : [...state.inventory, { ...itemDef, quantity } as InventoryItem];

    return {
    ...state,
    inventory: newInventory,
    logs: [`Acquired ${itemDef.name} x${quantity}.`, ...state.logs],
    };
};

export const handlePayCost = (state: GameState, payload: { gold?: number; items?: { id: string; count: number }[] }): GameState => {
    const { gold, items } = payload;
    let newGold = state.stats.gold;
    let newInventory = [...state.inventory];

    if (gold) newGold -= gold;
    if (items) {
        items.forEach(costItem => {
            newInventory = newInventory.map(invItem => {
                if (invItem.id === costItem.id) {
                    return { ...invItem, quantity: invItem.quantity - costItem.count };
                }
                return invItem;
            }).filter(i => i.quantity > 0);
        });
    }
    return {
        ...state,
        stats: { ...state.stats, gold: newGold },
        inventory: newInventory
    };
};

export const handleBuyMarketItems = (state: GameState, payload: { items: { id: string; count: number }[]; totalCost: number }): GameState => {
    const { items, totalCost } = payload;

    const newGold = state.stats.gold - totalCost;
    if (newGold < 0) return state; 

    let newInventory = [...state.inventory];
    let newTierLevel = state.stats.tierLevel;
    let newForgeState = { ...state.forge };
    let logUpdates: string[] = [`Bought supplies for ${totalCost} Gold.`];
    let newMarketStock = { ...state.marketStock };
    let newUnlockedTabs = [...state.unlockedTabs];
    let newActiveTutorialScene = state.activeTutorialScene;

    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logUpdates.unshift("Access granted: Inventory facility is now operational.");
    }

    items.forEach(buyItem => {
            // Update stock
            newMarketStock[buyItem.id] = Math.max(0, (newMarketStock[buyItem.id] || 0) - buyItem.count);

            if (buyItem.id === 'scroll_t2') {
                newTierLevel = Math.max(newTierLevel, 2);
                logUpdates.unshift('Upgrade Complete: Market Tier 2 Unlocked!');
                return; 
            }
            if (buyItem.id === 'scroll_t3') {
                newTierLevel = Math.max(newTierLevel, 3);
                logUpdates.unshift('Upgrade Complete: Market Tier 3 Unlocked!');
                return; 
            }
            if (buyItem.id === 'furnace') {
                newForgeState.hasFurnace = true;
                if (newTierLevel === 0) newTierLevel = 1; 
                logUpdates.unshift('Furnace acquired! The restoration process has begun.');

                // Set the next tutorial scene mode
                newActiveTutorialScene = 'FURNACE_RESTORED';

                return; 
            }
            if (buyItem.id === 'workbench') {
                newForgeState.hasWorkbench = true;
                logUpdates.unshift('Workbench installed! You can now craft leather and wood equipment.');
                return;
            }
            const itemDef = Object.values(MATERIALS).find(i => i.id === buyItem.id);
            if (itemDef) {
                const existingItem = newInventory.find(i => i.id === buyItem.id);
                if (existingItem) {
                    newInventory = newInventory.map(i => i.id === buyItem.id ? { ...i, quantity: i.quantity + buyItem.count } : i);
                } else {
                    newInventory.push({ ...itemDef, quantity: buyItem.count } as InventoryItem);
                }
            }
    });

    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: newGold, 
            tierLevel: newTierLevel,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseMarket: state.stats.dailyFinancials.expenseMarket + totalCost
            }
        },
        forge: newForgeState,
        inventory: newInventory,
        marketStock: newMarketStock,
        unlockedTabs: newUnlockedTabs,
        activeTutorialScene: newActiveTutorialScene,
        logs: [...logUpdates, ...state.logs]
    };
};

export const handleInstallFurnace = (state: GameState): GameState => {
    let newUnlockedTabs = [...state.unlockedTabs];
    // No automatic tab unlock here anymore

    return {
        ...state,
        forge: { ...state.forge, hasFurnace: true },
        unlockedTabs: newUnlockedTabs,
        logs: ['The Furnace has been installed! The forge comes alive.', ...state.logs]
    };
};

export const handleSellItem = (state: GameState, payload: { itemId: string; count: number; price: number; equipmentInstanceId?: string; customer?: Mercenary }): GameState => {
    const { itemId, count, price, equipmentInstanceId, customer } = payload;

    let newInventory = [...state.inventory];
    let itemName = 'Item';
    let newKnownMercenaries = [...state.knownMercenaries];
    let logMessage = '';
    let newActiveCustomer = state.activeCustomer;
    let newTutorialStep = state.tutorialStep;

    const isShopSale = !!customer;

    if (equipmentInstanceId) {
        const itemIndex = newInventory.findIndex(i => i.id === equipmentInstanceId);
        if (itemIndex > -1) {
            itemName = newInventory[itemIndex].name;
            newInventory.splice(itemIndex, 1);
        }
    } else {
        newInventory = newInventory.map(item => {
            if (item.id === itemId) {
                itemName = item.name;
                return { ...item, quantity: item.quantity - count };
            }
            return item;
        }).filter(i => i.quantity > 0);
    }

    if (customer) {
        const existingMercIdx = newKnownMercenaries.findIndex(m => m.id === customer.id);

        if (existingMercIdx > -1) {
            const merc = { ...newKnownMercenaries[existingMercIdx] };
            merc.affinity = Math.min(100, (merc.affinity || 0) + 2); 
            merc.visitCount = (merc.visitCount || 0) + 1;
            merc.lastVisitDay = state.stats.day;
            newKnownMercenaries[existingMercIdx] = merc;
            logMessage = `Sold ${itemName} to ${customer.name}. Affinity rose to ${merc.affinity}.`;
        } else {
            const newMerc: Mercenary = {
                ...customer,
                affinity: 2,
                visitCount: 1,
                lastVisitDay: state.stats.day,
                expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
                currentXp: 0,
                xpToNextLevel: 100,
                status: 'VISITOR' // Explicitly set status to VISITOR for new contacts
            };
            newKnownMercenaries.push(newMerc);
            logMessage = `Sold ${itemName} to ${customer.name}. (New Contact)`;
        }

        // Tutorial completion transition: Move to monologue after Pip's sale
        if (newTutorialStep === 'SELL_ITEM_GUIDE' && customer.id === 'pip_green') {
            newTutorialStep = 'TUTORIAL_END_MONOLOGUE';
        }

        if (state.activeCustomer && state.activeCustomer.mercenary.id === customer.id) {
            newActiveCustomer = null; 
        }
    } else {
        logMessage = `Sold ${itemName} for ${price} Gold.`;
    }

    return {
        ...state,
        inventory: newInventory,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold + price,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeShop: state.stats.dailyFinancials.incomeShop + (isShopSale ? price : 0),
                incomeInventory: state.stats.dailyFinancials.incomeInventory + (!isShopSale ? price : 0)
            }
        },
        knownMercenaries: newKnownMercenaries,
        activeCustomer: newActiveCustomer,
        tutorialStep: newTutorialStep,
        logs: [logMessage, ...state.logs]
    };
};

export const handleUseItem = (state: GameState, payload: { itemId: string }): GameState => {
    const { itemId } = payload;
    const inventoryItem = state.inventory.find(i => i.id === itemId);

    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    let newStats = { ...state.stats };
    let newUnlockedRecipes = [...(state.unlockedRecipes || [])];
    let logMsg = '';
    let itemUsed = false;

    // Logic per Item ID
    if (itemId === 'energy_potion') {
        const recoverAmount = 25;
        if (newStats.energy >= newStats.maxEnergy) {
            return {
                ...state,
                logs: [`Energy is already full!`, ...state.logs]
            };
        }
        newStats.energy = Math.min(newStats.maxEnergy, newStats.energy + recoverAmount);
        logMsg = `Consumed Energy Potion. +${recoverAmount} Energy.`;
        itemUsed = true;
    } 
    else if (itemId === 'recipe_scroll_bronze_longsword') {
        const targetRecipeId = 'sword_bronze_long_t1';
        if (newUnlockedRecipes.includes(targetRecipeId)) {
            return {
                ...state,
                logs: [`You already know the techniques in this scroll.`, ...state.logs]
            };
        }
        newUnlockedRecipes.push(targetRecipeId);
        logMsg = `Studied the scroll. Bronze Longsword recipe unlocked!`;
        itemUsed = true;
    }

    if (!itemUsed) return state;

    // Deduct Item
    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    return {
        ...state,
        stats: newStats,
        inventory: newInventory,
        unlockedRecipes: newUnlockedRecipes,
        logs: [logMsg, ...state.logs]
    };
};

