                    <span className="text-sm md:text-lg font-bold font-mono">{shopQueue.length}</span>
                </div>
            </div>
        )}

        {/* Mercenary Info HUD */}
        {isShopOpen && activeCustomer && tutorialStep !== 'TUTORIAL_END_MONOLOGUE' && (
